(() => {
  const TILE_SELECTOR = 'a[href*="/p/pg/"]';
  const BUTTON_CLASS = 'kms-configure-button';
  const TILE_CONTAINER_CLASS = 'kms-configure-tile-container';
  const CONFIGURATOR_PATH = '/__service/lens-configuration-service/lens/configuration';

  const getProductSku = (productUrl) => {
    const url = new URL(productUrl, window.location.origin);
    const skuSegment = url.pathname
      .split('/')
      .filter(Boolean)
      .reverse()
      .find((segment) => /^\d+$/.test(segment));

    return skuSegment || '';
  };

  const getConfiguratorUrl = (sku) => {
    const url = new URL(CONFIGURATOR_PATH, window.location.origin);

    url.searchParams.set('SKU', sku);
    url.searchParams.set('process', '');

    return `${url.pathname}?SKU=${encodeURIComponent(sku)}&process=`;
  };

  const isProductTile = (tile) => (
    /ProductTile_productTile/.test(tile.className || '')
    && Boolean(getProductSku(tile.href))
  );

  const redirectToConfigurator = (productUrl) => {
    const sku = getProductSku(productUrl);

    if (!sku) {
      window.location.assign(productUrl);
      return;
    }

    window.location.assign(getConfiguratorUrl(sku));
  };

  const positionButton = (tile, tileContainer, button) => {
    const productImage = tile.querySelector('[class*="ProductTile_productImage"]');

    if (!productImage) {
      return;
    }

    const containerRect = tileContainer.getBoundingClientRect();
    const imageRect = productImage.getBoundingClientRect();
    const topPosition = Math.max(imageRect.bottom - containerRect.top - 44, 0);

    button.style.setProperty('--kms-configure-button-top', `${topPosition}px`);
  };

  const createButton = (tile, tileContainer) => {
    const button = document.createElement('button');

    button.className = BUTTON_CLASS;
    button.type = 'button';
    button.textContent = 'Konfigurieren';
    button.setAttribute('aria-label', 'Produkt mit Sehstärke konfigurieren');
    positionButton(tile, tileContainer, button);

    Kameleoon.API.Utils.addUniversalClickListener(button, (event) => {
      event.preventDefault();
      event.stopPropagation();
      redirectToConfigurator(tile.href);
    });

    Kameleoon.API.Utils.setTimeout(() => positionButton(tile, tileContainer, button), 400);

    return button;
  };

  const addButtonToTile = (tile) => {
    const tileContainer = tile.parentElement;

    if (!tileContainer) {
      return;
    }

    const existingButton = tileContainer.querySelector(`.${BUTTON_CLASS}`);

    tileContainer.classList.add(TILE_CONTAINER_CLASS);

    if (existingButton) {
      positionButton(tile, tileContainer, existingButton);
      return;
    }

    tileContainer.appendChild(createButton(tile, tileContainer));
  };

  const applyConfigurationButtons = (elements) => {
    const productTiles = Array.from(elements).filter(isProductTile);

    productTiles.forEach(addButtonToTile);
  };

  Kameleoon.API.Core.runWhenElementPresent(TILE_SELECTOR, applyConfigurationButtons);
})();

(() => {
  const SELECTORS = {
    existingHeading: 'h2',
    insertedBlock: '[data-kam-reading-pack]'
  };

  const ASSETS = {
    glasses: 'https://media.kameleoon.com/images/4377d601-b7d0-4fe3-94cb-cfc72450d873',
    pouch: 'https://media.kameleoon.com/images/1ffa3c56-0c2c-42ab-818a-8d39a44dc8d9',
    sunglasses: 'https://media.kameleoon.com/images/15e4f5bb-fe1a-4594-a111-127558bd80dc'
  };

  const getExistingReadingPack = () => {
    const headings = Array.from(document.querySelectorAll(SELECTORS.existingHeading));
    const readingPackHeading = headings.find((heading) => heading.textContent.trim() === 'Reading Pack');

    return readingPackHeading ? readingPackHeading.closest('.rp') : null;
  };

  const createImage = (src, alt, className) => {
    const image = document.createElement('img');
    image.src = src;
    image.alt = alt;
    image.className = className;
    image.loading = 'eager';

    return image;
  };

  const createIntro = () => {
    const intro = document.createElement('div');
    intro.className = 'kam-reading-pack__intro';

    const title = document.createElement('h2');
    title.textContent = 'Reading Pack';

    const copyWrapper = document.createElement('div');
    const offer = document.createElement('p');
    const gift = document.createElement('p');

    offer.textContent = '5€ off your duo';
    gift.textContent = '+ a complimentary travel pouch';

    copyWrapper.append(offer, gift);
    intro.append(title, copyWrapper);

    return intro;
  };

  const createProducts = () => {
    const products = document.createElement('div');
    products.className = 'kam-reading-pack__products';

    products.append(
