  const POPUP_STORAGE_KEY = 'scandicSummerCampaignPopupOptOut';
  const CAMPAIGN_URL = 'https://www.scandichotels.com/en/offers/summer-campaign';
  const POPUP_DELAY = 10000;

  const isHomePage = () => {
    const normalizedPath = window.location.pathname.replace(/\/$/, '');

    return normalizedPath === '' || normalizedPath === '/en';
  };

  const hasOptedOut = () => {
    try {
      return Kameleoon.API.Data.readLocalData(POPUP_STORAGE_KEY) === 'true';
    } catch (error) {
      return window.sessionStorage.getItem(POPUP_STORAGE_KEY) === 'true';
    }
  };

  const saveOptOut = () => {
    try {
      Kameleoon.API.Data.writeLocalData(POPUP_STORAGE_KEY, 'true', false);
    } catch (error) {
      window.sessionStorage.setItem(POPUP_STORAGE_KEY, 'true');
    }
  };

  const createPopupMarkup = () => {
    const overlay = document.createElement('div');
    overlay.className = 'kameleoonInsert scandic-summer-popup-overlay';
    overlay.setAttribute('role', 'presentation');
    overlay.innerHTML = `
      <div class="kameleoonInsert scandic-summer-popup-dialog" role="dialog" aria-modal="true" aria-labelledby="scandic-summer-popup-title" aria-describedby="scandic-summer-popup-copy">
        <button class="kameleoonInsert scandic-summer-popup-close" type="button" aria-label="Close summer campaign popup">×</button>
        <div class="kameleoonInsert scandic-summer-popup-image" aria-hidden="true"></div>
        <div class="kameleoonInsert scandic-summer-popup-content">
          <p class="kameleoonInsert scandic-summer-popup-kicker">Don’t miss out</p>
          <h2 class="kameleoonInsert scandic-summer-popup-title" id="scandic-summer-popup-title">Book summer from €72/night</h2>
          <p class="kameleoonInsert scandic-summer-popup-copy" id="scandic-summer-popup-copy">Secure your summer stay from just €72. Visit one of our 280 hotels across 6 countries this summer.</p>
          <a class="kameleoonInsert scandic-summer-popup-cta" href="${CAMPAIGN_URL}">Explore the offer</a>
        </div>
      </div>
    `;

    return overlay;
  };

  const closePopup = (overlay) => {
    overlay.classList.remove('is-visible');
    Kameleoon.API.Utils.setTimeout(() => {
      overlay.remove();
    }, 260);
  };

  const bindPopupEvents = (overlay) => {
    const closeButton = overlay.querySelector('.scandic-summer-popup-close');
    const cta = overlay.querySelector('.scandic-summer-popup-cta');

    Kameleoon.API.Utils.addUniversalClickListener(closeButton, (event) => {
      event.preventDefault();
      event.stopPropagation();
      saveOptOut();
      closePopup(overlay);
    });

    Kameleoon.API.Utils.addUniversalClickListener(cta, () => {
      saveOptOut();
    });
  };

  const showPopup = () => {
    if (!isHomePage() || hasOptedOut() || document.querySelector('.scandic-summer-popup-overlay')) {
      return;
    }

    const overlay = createPopupMarkup();
    document.body.appendChild(overlay);
    bindPopupEvents(overlay);

    Kameleoon.API.Utils.setTimeout(() => {
      overlay.classList.add('is-visible');
    }, 50);
  };

