(() => {
  const FORM_SELECTOR = 'form#searchForm';
  const EXPANDED_CLASS = 'kam-criteria-expanded';
  const READY_ATTRIBUTE = 'data-kam-criteria-ready';

  const getElements = (form) => ({
    container: form.querySelector('.container_search'),
    location: form.querySelector('.col_lieu'),
    budget: form.querySelector('.col_budget'),
    pieces: form.querySelector('.col_pieces'),
    criteria: form.querySelector('.col_criteres'),
    cta: form.querySelector('.col_bouton')
  });

  const createTier = (className) => {
    const tier = document.createElement('div');
    tier.className = `${className} kameleoonInsert`;
    return tier;
  };

  const createToggle = () => {
    const toggle = document.createElement('button');
    toggle.type = 'button';
    toggle.className = 'kam-criteria-toggle kameleoonInsert';
    toggle.setAttribute('aria-expanded', 'false');
    toggle.innerHTML = '<span>Plus de critères</span><svg viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M6 9l6 6 6-6"/></svg>';
    return toggle;
  };

  const setToggleState = (form, toggle, isExpanded) => {
    form.classList.toggle(EXPANDED_CLASS, isExpanded);
    toggle.setAttribute('aria-expanded', String(isExpanded));
    toggle.querySelector('span').textContent = isExpanded ? 'Moins de critères' : 'Plus de critères';
  };

  const addToggleListener = (form, toggle) => {
    Kameleoon.API.Utils.addEventListener(toggle, 'click', () => {
      const nextExpandedState = !form.classList.contains(EXPANDED_CLASS);
      setToggleState(form, toggle, nextExpandedState);
    });
  };

  const buildTwoTierLayout = (form) => {
    if (form.getAttribute(READY_ATTRIBUTE) === 'true') return;

    const { container, location, budget, pieces, criteria, cta } = getElements(form);
    if (!container || !location || !budget || !cta) return;

    form.setAttribute(READY_ATTRIBUTE, 'true');

    const tier1 = createTier('kam-criteria-tier kam-criteria-tier-1');
    const toggleRow = createTier('kam-criteria-toggle-row');
    const tier2 = createTier('kam-criteria-tier kam-criteria-tier-2');
    const toggle = createToggle();

    const budgetLabel = budget.querySelector('.fake_label');
    if (budgetLabel) budgetLabel.textContent = 'Budget max';

    tier1.append(location, budget, cta);

    if (criteria) {
      const nativeCriteriaLabel = criteria.querySelector('.toggle_criteres .fake_label');
      if (nativeCriteriaLabel) nativeCriteriaLabel.textContent = 'Critères';
      tier2.append(criteria);
    }

    if (pieces) tier2.prepend(pieces);

    toggleRow.append(toggle);
    container.append(tier1, toggleRow, tier2);

    setToggleState(form, toggle, false);
    addToggleListener(form, toggle);
  };

  Kameleoon.API.Core.runWhenElementPresent(FORM_SELECTOR, (forms) => {
    forms.forEach(buildTwoTierLayout);
  });
})();

