(() => {
  const SELECTORS = {
    carousel: '[data-testid="carousel-container"]',
    recommendedHeading: 'h2'
  };

  const CLASS_NAMES = {
    initialized: 'kameleoon-recommended-carousel',
    scroller: 'kameleoon-recommended-carousel__scroller',
    item: 'kameleoon-recommended-carousel__item'
  };

  const SLIDE_DELAY = 2000;

  const getRecommendedSection = () => Array.from(document.querySelectorAll(SELECTORS.recommendedHeading))
    .find((heading) => heading.textContent.trim().toLowerCase() === 'recommended recipes')
    ?.closest('section');

  const getRecommendedCarousel = () => {
    const section = getRecommendedSection();

    if (!section) {
      return null;
    }

    return section.querySelector(SELECTORS.carousel);
  };

  const getCarouselItems = (carousel) => Array.from(carousel.children)
    .filter((item) => item.tagName.toLowerCase() === 'li');

  const scrollToSlide = (carousel, slideIndex) => {
    const items = getCarouselItems(carousel);
    const targetItem = items[slideIndex];

    if (!targetItem) {
      return;
    }

    carousel.scrollTo({
      left: targetItem.offsetLeft,
      behavior: 'smooth'
    });
  };

  const createAutoplay = (carousel) => {
    const items = getCarouselItems(carousel);
    let activeSlide = Math.max(0, items.findIndex((item) => item.getBoundingClientRect().left >= carousel.getBoundingClientRect().left - 2));
    let timerId = null;

    const stop = () => {
      if (timerId !== null) {
        Kameleoon.API.Utils.clearInterval(timerId);
        timerId = null;
      }
    };

    const start = () => {
      stop();
      timerId = Kameleoon.API.Utils.setInterval(() => {
        const currentItems = getCarouselItems(carousel);

        if (currentItems.length < 2) {
          return;
        }

        activeSlide = (activeSlide + 1) % currentItems.length;
        scrollToSlide(carousel, activeSlide);
      }, SLIDE_DELAY);
    };

    Kameleoon.API.Utils.addEventListener(carousel, 'mouseenter', stop);
    Kameleoon.API.Utils.addEventListener(carousel, 'mouseleave', start);
    Kameleoon.API.Utils.addEventListener(carousel, 'focusin', stop);
    Kameleoon.API.Utils.addEventListener(carousel, 'focusout', start);

    start();
  };

  const setupRecommendedCarousel = () => {
    const carousel = getRecommendedCarousel();

    if (!carousel || carousel.classList.contains(CLASS_NAMES.initialized)) {
      return;
    }

    const wrapper = carousel.closest('[data-testid="horizontal-scroller-undefined"]');
    const items = getCarouselItems(carousel);

    if (!wrapper || items.length === 0) {
      return;
    }

    wrapper.classList.add(CLASS_NAMES.initialized);
    carousel.classList.add(CLASS_NAMES.scroller);
    items.forEach((item) => item.classList.add(CLASS_NAMES.item));
    carousel.scrollLeft = 0;

    createAutoplay(carousel);
  };

  Kameleoon.API.Core.runWhenElementPresent(SELECTORS.carousel, setupRecommendedCarousel);
})();

(() => {
  const BANNER_ID = 'kameleoon-sales-countdown-banner';
  const SESSION_KEY = 'kameleoonSalesCountdownDismissed';
  const SALES_URL = 'https://www.petit-bateau.fr/soldes/au-menu-des-soldes/selection-60/';
  const SALES_END_DATE = new Date('2026-07-21T23:59:00+02:00');

  const getRemainingTime = () => {
    const timeLeft = SALES_END_DATE.getTime() - Date.now();

    if (timeLeft <= 0) {
      return null;
    }

    return {
      days: Math.floor(timeLeft / 86400000),
      hours: Math.floor((timeLeft % 86400000) / 3600000),
      minutes: Math.floor((timeLeft % 3600000) / 60000),
      seconds: Math.floor((timeLeft % 60000) / 1000)
    };
  };

  const formatNumber = (value) => String(value).padStart(2, '0');

  const buildTimerItem = (value, label, className) => `
    <span class="kameleoon-countdown-timer-item">
      <b class="${className}">${formatNumber(value)}</b>
      <small>${label}</small>
    </span>
  `;

  const buildBanner = () => {
    const banner = document.createElement('aside');
    banner.id = BANNER_ID;
    banner.className = 'kameleoonInsert kameleoon-countdown-banner';
    banner.setAttribute('role', 'region');
    banner.setAttribute('aria-label', 'Compte à rebours des soldes');

    banner.innerHTML = `
      <button class="kameleoon-countdown-close" type="button" aria-label="Fermer le bandeau">×</button>
      <div class="kameleoon-countdown-content">
        <div class="kameleoon-countdown-copy">
          <strong>SOLDES jusqu’à <span>-60%</span></strong>
        </div>
        <div class="kameleoon-countdown-timer" aria-label="Temps restant avant la fin des soldes"></div>
        <a class="kameleoon-countdown-cta" href="${SALES_URL}" aria-label="Accéder aux soldes">SOLDES</a>
      </div>
    `;

    return banner;
  };

  const hideBannerForSession = (banner) => {
    sessionStorage.setItem(SESSION_KEY, 'true');
    banner.classList.add('kameleoon-countdown-banner--hidden');

    Kameleoon.API.Utils.setTimeout(() => {
      banner.remove();
    }, 260);
  };

  const updateTimer = (banner) => {
    const remainingTime = getRemainingTime();
    const timer = banner.querySelector('.kameleoon-countdown-timer');

    if (!remainingTime || !timer) {
      banner.remove();
      return false;
    }

    timer.innerHTML = [
      buildTimerItem(remainingTime.days, 'jours', 'kameleoon-countdown-days'),
      buildTimerItem(remainingTime.hours, 'heures', 'kameleoon-countdown-hours'),
      buildTimerItem(remainingTime.minutes, 'min', 'kameleoon-countdown-minutes'),
      buildTimerItem(remainingTime.seconds, 'sec', 'kameleoon-countdown-seconds')
    ].join('');

    return true;
  };

  const bindEvents = (banner) => {
    const closeButton = banner.querySelector('.kameleoon-countdown-close');
    const cta = banner.querySelector('.kameleoon-countdown-cta');

    if (closeButton) {
      Kameleoon.API.Utils.addUniversalClickListener(closeButton, () => {
        hideBannerForSession(banner);
      });
    }

    if (cta) {
      Kameleoon.API.Utils.addUniversalClickListener(cta, () => {
        sessionStorage.setItem(SESSION_KEY, 'true');
      });
    }
  };

  const initCountdownBanner = () => {
    if (sessionStorage.getItem(SESSION_KEY) === 'true' || document.getElementById(BANNER_ID)) {
      return;
    }

    const banner = buildBanner();

    if (!updateTimer(banner)) {
      return;
    }

    document.body.appendChild(banner);
    bindEvents(banner);

    const intervalId = Kameleoon.API.Utils.setInterval(() => {
      if (!document.body.contains(banner) || !updateTimer(banner)) {
        Kameleoon.API.Utils.clearInterval(intervalId);
      }
    }, 1000);
  };

  Kameleoon.API.Core.runWhenElementPresent('body', initCountdownBanner);
})();

