(() => {
  const aboutSelector = 'section#about';
  const summaryText = 'Full-stack engineer and technical account manager focused on building reliable, performant systems and turning experimentation into measurable product growth. Experienced across Japan, Canada, and France, supporting complex implementations and data-informed decision-making.';
  const expandedLabel = 'Show less';
  const collapsedLabel = 'Read the full background';

  const getDirectParagraphs = (container) => Array.from(container.children).filter((child) => child.tagName === 'P');

  const removeValidationPreview = (about) => {
    const preview = about.querySelector(':scope > .kam-about-preview');

    if (preview) {
      preview.remove();
    }
  };

  const createSummaryParagraph = () => {
    const paragraph = document.createElement('p');
    paragraph.className = 'kameleoonInsert kam-about-summary';
    paragraph.textContent = summaryText;

    return paragraph;
  };

  const createBackgroundElement = () => {
    const background = document.createElement('div');
    background.className = 'kameleoonInsert kam-about-background';

    const toggle = document.createElement('button');
    toggle.className = 'kameleoonInsert kam-about-toggle';
    toggle.type = 'button';
    toggle.setAttribute('aria-expanded', 'false');
    toggle.textContent = collapsedLabel;

    const content = document.createElement('div');
    content.className = 'kameleoonInsert kam-about-background-content';
    content.hidden = true;

    background.append(toggle, content);

    Kameleoon.API.Utils.addUniversalClickListener(toggle, (event) => {
      event.preventDefault();

      const scrollX = window.scrollX;
      const scrollY = window.scrollY;
      const shouldExpand = content.hidden;

      content.hidden = !shouldExpand;
      toggle.textContent = shouldExpand ? expandedLabel : collapsedLabel;
      toggle.setAttribute('aria-expanded', String(shouldExpand));

      if (shouldExpand) {
        content.insertAdjacentElement('afterend', toggle);
      } else {
        content.insertAdjacentElement('beforebegin', toggle);
      }

      window.requestAnimationFrame(() => {
        window.scrollTo(scrollX, scrollY);
      });
    });

    return { background, content };
  };

  const enhanceAboutIntro = (about) => {
    if (!about || about.querySelector(':scope > .kam-about-summary')) return;

    removeValidationPreview(about);

    const paragraphs = getDirectParagraphs(about);
    if (paragraphs.length < 3) return;

    const summaryParagraph = createSummaryParagraph();
    const { background, content } = createBackgroundElement();
    const firstParagraph = paragraphs[0];
    const paragraphsToReplace = paragraphs.slice(0, 2);
    const backgroundParagraphs = paragraphs.slice(2);

    firstParagraph.insertAdjacentElement('beforebegin', summaryParagraph);
    summaryParagraph.insertAdjacentElement('afterend', background);

    backgroundParagraphs.forEach((paragraph) => {
      paragraph.removeAttribute('style');
      content.appendChild(paragraph);
    });

    paragraphsToReplace.forEach((paragraph) => {
      paragraph.remove();
    });
  };

  Kameleoon.API.Core.runWhenElementPresent(aboutSelector, (elements) => {
    elements.forEach((element) => enhanceAboutIntro(element));
  });
})();

