    }, AUTOPLAY_DELAY);
  };

  const bindPauseInteractions = (carousel, state, nextButton) => {
    const api = getKameleoonApi();

    api.Utils.addEventListener(carousel, 'mouseenter', () => {
      state.isHovering = true;
      stopAutoplay(state);
    });

    api.Utils.addEventListener(carousel, 'mouseleave', () => {
      state.isHovering = false;
      scheduleAutoplay(state, nextButton);
    });

    api.Utils.addEventListener(carousel, 'focusin', () => {
      state.hasFocus = true;
      stopAutoplay(state);
    });

    api.Utils.addEventListener(carousel, 'focusout', (event) => {
      if (carousel.contains(event.relatedTarget)) return;

      state.hasFocus = false;
      scheduleAutoplay(state, nextButton);
    });

    api.Utils.addEventListener(document, 'visibilitychange', () => {
      if (document.hidden) {
        stopAutoplay(state);
        return;
      }

      scheduleAutoplay(state, nextButton);
    });
  };

  const bindManualControls = (carousel, state, nextButton, prevButton) => {
    const restartAutoplay = () => {
      scheduleAutoplay(state, nextButton);
    };

    getKameleoonApi().Utils.addUniversalClickListener(nextButton, restartAutoplay);

    if (prevButton) {
      getKameleoonApi().Utils.addUniversalClickListener(prevButton, restartAutoplay);
    }
  };

  const initialisePartnerOffersAutoplay = (carousel) => {
    if (!carousel || carousel.dataset.kameleoonPartnerOffersAutoplay === 'true') return;

    const { nextButton, prevButton } = getCarouselControls(carousel);
    if (!nextButton) return;

    carousel.dataset.kameleoonPartnerOffersAutoplay = 'true';
    carousel.classList.add('kam-partner-offers-autoplay');
    removePreviewControls(carousel);

    const state = {
      timeoutId: null,
      isHovering: false,
      hasFocus: false
    };

    bindPauseInteractions(carousel, state, nextButton);
    bindManualControls(carousel, state, nextButton, prevButton);
    scheduleAutoplay(state, nextButton);
  };

  getKameleoonApi().Core.runWhenElementPresent(PARTNER_OFFERS_SELECTOR, (elements) => {
    elements.forEach(initialisePartnerOffersAutoplay);
  });
})();

