    .find((button) => getCleanText(button) === 'Add to Cart' && !button.hasAttribute(STICKY_ATC_ATTRIBUTE));

  const fallbackToBuySection = () => {
    const buySection = document.querySelector('#buyNowSection');

    if (buySection) {
      buySection.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  const addStickyButtonListener = (button) => {
    Kameleoon.API.Utils.addUniversalClickListener(button, (event) => {
      event.preventDefault();

      const mainAddToCartButton = findMainAddToCartButton();

      if (mainAddToCartButton && !mainAddToCartButton.disabled) {
        mainAddToCartButton.click();
        return;
      }

      fallbackToBuySection();
    });
  };

  const buildStickyAddToCartButton = (goToBuyLink) => {
    const button = document.createElement('button');

    button.type = 'button';
    button.className = `${goToBuyLink.className} ${INSERTED_CLASS}`;
    button.setAttribute(STICKY_ATC_ATTRIBUTE, 'true');
    button.setAttribute('aria-label', 'Add Aerox 9 Wireless to cart');
    button.textContent = 'Add to Cart';

    return button;
  };

  const replaceGoToBuyCta = (goToBuyLink) => {
    if (!goToBuyLink || goToBuyLink.hasAttribute(STICKY_ATC_ATTRIBUTE)) {
      return;
    }

    const existingStickyButton = goToBuyLink.parentElement.querySelector(`[${STICKY_ATC_ATTRIBUTE}]`);

    if (existingStickyButton) {
      return;
    }

    const stickyAddToCartButton = buildStickyAddToCartButton(goToBuyLink);
    goToBuyLink.replaceWith(stickyAddToCartButton);
    addStickyButtonListener(stickyAddToCartButton);
  };

  Kameleoon.API.Core.runWhenElementPresent(STICKY_ATC_SELECTOR, (elements) => {
    elements.forEach(replaceGoToBuyCta);
  });
})();

